import styled from 'styled-components';

import Card from '../structure/Card';

const Message = styled(Card)`
  font-size: 18px;
  color: ${({ isDark }) =>
    isDark ? 'rgba(255, 255, 255, 0.7)' : 'rgba(0, 0, 0, 0.35)'};
`;

Message.defaultProps = {
  ...Card.defaultProps,
  w: 'fit-content',
  textAlign: 'center',
};

export default Message;
